import{_ as l,o as a,c as e,ag as t}from"./chunks/framework.DXGyWiRo.js";const _=JSON.parse('{"title":"开放技能接入审核规范","description":"","frontmatter":{"title":"开放技能接入审核规范"},"headers":[],"relativePath":"custom-biz/skill-studio/review-guide.md","filePath":"custom-biz/skill-studio/review-guide.md","lastUpdated":null}'),r={name:"custom-biz/skill-studio/review-guide.md"};function o(s,i,u,d,n,h){return a(),e("div",null,[...i[0]||(i[0]=[t('<h1 id="目-录" tabindex="-1">目 录 <a class="header-anchor" href="#目-录" aria-label="Permalink to &quot;目 录&quot;">​</a></h1><ol><li>技能名称和别名</li><li>图标</li><li>描述</li><li>技能内容</li><li>审核时效</li></ol><p>在开放技能开发完成并测试通过后，就可以将技能提交AIUI审核，审核完成后你的技能就可以在技能商店上架并服务于广大用户了。</p><h2 id="技能名称和别名" tabindex="-1">技能名称和别名 <a class="header-anchor" href="#技能名称和别名" aria-label="Permalink to &quot;技能名称和别名&quot;">​</a></h2><ul><li>名称长度应介于2-8个字之间，不能包含特殊字符。若名称中包含英文可能会造成用户无法进入你的技能。</li><li>我们不建议名称使用生僻字、生僻词组，否则用户会因为不会读而无法进入你的技能。</li><li>名称中不能包含AIUI中用于进入技能的词汇，如：“打开”，“启动”，“进入”等。</li><li>名称中不能包含AIUI的通用唤醒词，如：“小飞”、“蓝小飞”、“小飞小飞”、“来小飞”等。</li><li>名称中不能包含AIUI常用指令，如：“查天气”，“我要听歌”，“打开空调”等。</li><li>为了减少重复，技能名称不得以电话、邮件、日历等广义归纳类、普遍且不具有识别性词语来命名。</li><li>技能名称、功能涉及第三方企业或产品的信息或其他内容时，需要有其相关方面的授权。</li><li>技能名称不得侵犯第三方知识产权（包括版权、商标和宣传权）。</li></ul><h2 id="图标" tabindex="-1">图标 <a class="header-anchor" href="#图标" aria-label="Permalink to &quot;图标&quot;">​</a></h2><ul><li>建议尺寸为 480 x 480 的 png 或 jpg 图片。</li><li>像素清晰，无水印。</li><li>避免图标存在透明区域或者白边，避免文字过多。</li><li>不可涉及版权问题。</li><li>具体可查看<a href="/custom-biz/skill-studio/icon-guide.html">技能图标图片规范</a></li></ul><h2 id="描述" tabindex="-1">描述 <a class="header-anchor" href="#描述" aria-label="Permalink to &quot;描述&quot;">​</a></h2><ul><li>详细描述功能，至少10个字，不超过200个字。</li><li>技能名称、摘要、功能描述与实际应用应有直接关联。</li><li>可以在描述信息中提供更多技能内的常用表达示例，为用户快速了解技能功能。</li></ul><h2 id="技能内容" tabindex="-1">技能内容 <a class="header-anchor" href="#技能内容" aria-label="Permalink to &quot;技能内容&quot;">​</a></h2><ul><li>保证技能的后端技能稳定可靠，快速响应用户请求，达到用户良好的使用预期。</li><li>运用日常用语，简洁直白，语气友好。</li><li>技能交互中涉及到与技能名称相关的内容，需与技能名称保持一致。</li><li>适用于技能的实际使用场景，可以成功调用功能。</li><li>技能内容不得侵犯第三方知识产权（包括版权、商标和宣传权）。</li><li>技能内容不能违反现有法律规范，不得出现粗俗，暴力，色情，反动等语句。</li><li>技能相关链接不得包含非法信息。</li></ul><h2 id="审核时效" tabindex="-1">审核时效 <a class="header-anchor" href="#审核时效" aria-label="Permalink to &quot;审核时效&quot;">​</a></h2><ul><li>审核一般会在提交审核后的3个工作日内完成，审核结果会通过短信的方式通知你。</li><li>若长时间未审核通过，或对审核结果有异议，可在平台上提交工单进行反馈。</li></ul>',13)])])}const m=l(r,[["render",o]]);export{_ as __pageData,m as default};
